// WebhookConfig represents the incoming JSON payload
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to validate and configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON body",
		})
	}

	// Validate the webhook URL is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create a custom HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a context with the 3-second timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create the GET request to validate the webhook URL
	req, err := http.NewRequestWithContext(reqCtx, "GET", config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error": "Failed to create validation request",
		})
	}

	// Send the request
	resp, err := client.Do(req)
	if err != nil {
		// Check if the error is due to timeout
		if err == context.DeadlineExceeded {
			return ctx.Status(fiber.StatusRequestTimeout).JSON(fiber.Map{
				"error": "Webhook URL validation timed out",
			})
		}
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Failed to reach webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the response status code is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL returned non-success status code",
			"status": resp.StatusCode,
		})
	}

	// Here you would typically save the configuration to a database or storage
	// For this example, we just return success

	return ctx.JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Define the route
	app.Post("/configure-webhook", ConfigureWebhook)

