// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
    // Check for private IPv4 ranges
    if ip4 := ip.To4(); ip4 != nil {
        // 10.0.0.0/8
        if ip4[0] == 10 {
            return true
        }
        // 172.16.0.0/12
        if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
            return true
        }
        // 192.168.0.0/16
        if ip4[0] == 192 && ip4[1] == 168 {
            return true
        }
        // 169.254.0.0/16 (link-local)
        if ip4[0] == 169 && ip4[1] == 254 {
            return true
        }
        // 127.0.0.0/8 (localhost)
        if ip4[0] == 127 {
            return true
        }
        // 0.0.0.0/8
        if ip4[0] == 0 {
            return true
        }
        // 224.0.0.0/4 (multicast)
        if ip4[0] >= 224 && ip4[0] <= 239 {
            return true
        }
        // 240.0.0.0/4 (reserved)
        if ip4[0] >= 240 {
            return true
        }
    }

    // Check for private IPv6 ranges
    if ip.To16() != nil && ip.To4() == nil {
        // Link-local IPv6 addresses
        if ip.IsLinkLocalUnicast() {
            return true
        }
        // Unique local addresses (fc00::/7)
        if ip[0] == 0xfc || ip[0] == 0xfd {
            return true
        }
        // Loopback address
        if ip.IsLoopback() {
            return true
        }
        // Multicast
        if ip.IsMulticast() {
            return true
        }
    }

    return false
}

// isValidHostname checks if hostname is valid and not pointing to private IP
func isValidHostname(hostname string) error {
    // Resolve the hostname to IP addresses
    ips, err := net.LookupIP(hostname)
    if err != nil {
        return fmt.Errorf("failed to resolve hostname: %v", err)
    }

    // Check each resolved IP
    for _, ip := range ips {
        if isPrivateIP(ip) {
            return fmt.Errorf("hostname resolves to private IP: %s", ip)
        }
    }

    return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Parse the JSON request body
    var req webhookRequest
    if err := ctx.BodyParser(&req); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Invalid JSON format",
        })
    }

    // Validate that webhook_url is provided
    if req.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "webhook_url is required",
        })
    }

    // Validate URL format
    parsedURL, err := url.ParseRequestURI(req.WebhookURL)
    if err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Invalid webhook URL format",
        })
    }

    // Ensure the URL has a valid scheme
    if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "webhook URL must use http or https scheme",
        })
    }

