)

// WebhookConfig defines the structure for the incoming JSON payload
type WebhookConfig struct {
    WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to validate and save a webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Parse the JSON body
    var config WebhookConfig
    if err := ctx.BodyParser(&config); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Invalid JSON format",
        })
    }

    // Validate that the webhook_url is provided
    if config.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "webhook_url is required",
        })
    }

    // Create a custom HTTP client with a 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Create a context with the 3-second timeout for the request
    reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create the test GET request
    req, err := http.NewRequestWithContext(reqCtx, "GET", config.WebhookURL, nil)
    if err != nil {
        return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
            "error": "Failed to create test request",
        })
    }

    // Execute the test request
    resp, err := client.Do(req)
    if err != nil {
        // Check if the error is due to timeout
        return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
            "error":   "Webhook URL validation failed",
            "details": err.Error(),
        })
    }
    defer resp.Body.Close()

    // Check if the response status code indicates success (2xx)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
            "error":      "Webhook URL returned a non-successful status code",
            "status_code": resp.StatusCode,
        })
    }

    // Here you would typically save the configuration to a database or persistent storage.
    // For this example, we simulate a successful save operation.

    // Return success response
    return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
        "message": "Webhook configured successfully",
        "url":     config.WebhookURL,
    })
}

func main() {
    app := fiber.New()

    // Define the route for the webhook configuration
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server
    err := app.Listen(":3000")
    if err != nil {
        panic(err)
    }
}

