package main

import (
    "context"
    "encoding/json"
    "net/http"
    "time"

    "github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the incoming JSON payload
type WebhookConfig struct {
    WebhookURL string `json:"webhook_url"`
}

// Response represents the standard JSON response
type Response struct {
    Success bool   `json:"success"`
    Message string `json:"message"`
}

// ConfigureWebhook handles the POST request to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
    var config WebhookConfig

    // Parse the JSON body
    if err := ctx.BodyParser(&config); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "Invalid JSON body",
        })
    }

    // Validate that the webhook_url is provided
    if config.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "webhook_url is required",
        })
    }

    // Create a custom HTTP client with a 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Create a context with the 3-second timeout
    reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create the test GET request
    req, err := http.NewRequestWithContext(reqCtx, "GET", config.WebhookURL, nil)
    if err != nil {
        return ctx.Status(fiber.StatusInternalServerError).JSON(Response{
            Success: false,
            Message: "Failed to create test request",
        })
    }

    // Execute the test request
    resp, err := client.Do(req)
    if err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "Webhook URL validation failed: " + err.Error(),
        })
    }
    defer resp.Body.Close()

    // Check if the response status code indicates success (2xx)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "Webhook URL returned non-success status code: " + resp.Status,
        })
    }

    // Here you would typically save the configuration to a database or persistent storage.
    // For this implementation, we simply acknowledge the success.

    return ctx.JSON(Response{
        Success: true,
        Message: "Webhook configured and validated successfully",
    })
}

func main() {
    app := fiber.New()

    // Define the route
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server
    err := app.Listen(":3000")
    if err != nil {
        panic(err)
    }
}

