)

// WebhookRequest defines the structure of the incoming JSON body
type WebhookRequest struct {
    WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Parse the request body
    var req WebhookRequest
    if err := ctx.BodyParser(&req); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Invalid JSON body",
        })
    }

    // Validate that the webhook_url is provided
    if req.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "webhook_url is required",
        })
    }

    // Create a custom HTTP client with a 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Create a context with the timeout
    clientCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create the test request (GET method)
    reqTest, err := http.NewRequestWithContext(clientCtx, http.MethodGet, req.WebhookURL, nil)
    if err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Invalid webhook URL format",
        })
    }

    // Send the test request
    resp, err := client.Do(reqTest)
    if err != nil {
        // Check if the error is due to timeout
        if err == context.DeadlineExceeded {
            return ctx.Status(fiber.StatusRequestTimeout).JSON(fiber.Map{
                "error": "Webhook URL test timed out",
            })
        }
        return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
            "error": "Failed to connect to webhook URL",
        })
    }
    defer resp.Body.Close()

    // Check if the response status code indicates success (2xx)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Webhook URL test failed",
            "status": resp.StatusCode,
        })
    }

    // Here you would typically save the configuration to a database or storage.
    // For this example, we simply return a success message.

    return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
        "message": "Webhook configured successfully",
        "url":     req.WebhookURL,
    })
}

func main() {
    app := fiber.New()

    // Define the route
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server
    err := app.Listen(":3000")
    if err != nil {
        panic(err)
    }
}

