import (
	"context"
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the incoming JSON structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to validate and save a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON body",
		})
	}

	// Validate the webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create a context with a 3-second timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new GET request to the webhook URL
	req, err := http.NewRequestWithContext(reqCtx, "GET", config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error": "Failed to create test request",
		})
	}

	// Execute the request using the default HTTP client
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		// Check if the error is due to context timeout
		if reqCtx.Err() == context.DeadlineExceeded {
			return ctx.Status(fiber.StatusRequestTimeout).JSON(fiber.Map{
				"error": "Webhook URL test timed out",
			})
		}
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error": "Failed to reach webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the response status code is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error": "Webhook URL returned non-success status",
			"status": resp.StatusCode,
		})
	}

	// Simulate saving the configuration (e.g., to a database or in-memory store)
	// In a real application, you would persist config.WebhookURL here.
	// For this example, we simply log it and return success.

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Define the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

