    "github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the structure for the incoming JSON request
type WebhookRequest struct {
    WebhookURL string `json:"webhook_url"`
}

// WebhookResponse defines the structure for the JSON response
type WebhookResponse struct {
    Success bool   `json:"success"`
    Message string `json:"message"`
}

// ConfigureWebhook handles the POST request to configure and test a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
    var req WebhookRequest

    // Parse the JSON body
    if err := ctx.BodyParser(&req); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
            Success: false,
            Message: "Invalid JSON format",
        })
    }

    // Validate that the webhook_url is provided
    if req.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
            Success: false,
            Message: "webhook_url is required",
        })
    }

    // Create a custom HTTP client with a 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Create a context with the 3-second timeout
    reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create the GET request to test the webhook URL
    httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.WebhookURL, nil)
    if err != nil {
        return ctx.Status(fiber.StatusInternalServerError).JSON(WebhookResponse{
            Success: false,
            Message: "Failed to create test request",
        })
    }

    // Execute the request
    resp, err := client.Do(httpReq)
    if err != nil {
        // Check if the error is due to timeout
        return ctx.Status(fiber.StatusServiceUnavailable).JSON(WebhookResponse{
            Success: false,
            Message: "Webhook test failed: " + err.Error(),
        })
    }
    defer resp.Body.Close()

    // Check if the response status code is successful (2xx)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
            Success: false,
            Message: "Webhook returned non-success status: " + resp.Status,
        })
    }

    // Here you would typically save the configuration to a database or storage.
    // For this example, we just return a success message.

    return ctx.JSON(WebhookResponse{
        Success: true,
        Message: "Webhook configured and tested successfully",
    })
}

func main() {
    app := fiber.New()

    // Define the route
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server on port 3000
    app.Listen(":3000")
}

