package main

import (
    "context"
    "encoding/json"
    "net/http"
    "time"

    "github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the incoming JSON payload
type WebhookConfig struct {
    WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Parse the request body
    var config WebhookConfig
    if err := ctx.BodyParser(&config); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Invalid JSON body",
        })
    }

    // Validate the webhook URL is present
    if config.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "webhook_url is required",
        })
    }

    // Create a custom HTTP client with 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Create the context with timeout for the request
    reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create the test request (GET method)
    req, err := http.NewRequestWithContext(reqCtx, "GET", config.WebhookURL, nil)
    if err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Invalid webhook URL format",
        })
    }

    // Execute the test request
    resp, err := client.Do(req)
    if err != nil {
        // Check if the error is due to timeout
        if err == context.DeadlineExceeded {
            return ctx.Status(fiber.StatusRequestTimeout).JSON(fiber.Map{
                "error": "Webhook URL request timed out",
            })
        }
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Failed to connect to webhook URL",
        })
    }
    defer resp.Body.Close()

    // Check if the response status code is valid (2xx range)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error": "Webhook URL returned non-success status code",
            "status": resp.StatusCode,
        })
    }

    // Here you would typically save the configuration to a database or storage
    // For this example, we just return success
    return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
        "message": "Webhook configured successfully",
        "url":     config.WebhookURL,
    })
}

func main() {
    app := fiber.New()

    // Define the route
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server
    err := app.Listen(":3000")
    if err != nil {
        panic(err)
    }
}

