type WebhookConfig struct {
    WebhookURL string `json:"webhook_url"`
}

// Response defines the structure for the JSON response
type Response struct {
    Success bool   `json:"success"`
    Message string `json:"message"`
}

// ConfigureWebhook handles the POST request to validate and save a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Parse the request body
    var config WebhookConfig
    if err := ctx.BodyParser(&config); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "Invalid JSON body",
        })
    }

    // Validate that the webhook_url is provided
    if config.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "webhook_url is required",
        })
    }

    // Create a context with a 3-second timeout for the test request
    // We use context.WithTimeout to ensure the request doesn't hang
    requestCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
    defer cancel()

    // Create a new HTTP request using the context
    req, err := http.NewRequestWithContext(requestCtx, http.MethodGet, config.WebhookURL, nil)
    if err != nil {
        return ctx.Status(fiber.StatusInternalServerError).JSON(Response{
            Success: false,
            Message: "Failed to create test request",
        })
    }

    // Execute the test request using the default HTTP client
    client := &http.Client{}
    resp, err := client.Do(req)
    if err != nil {
        // This typically catches context deadline exceeded (timeout) or connection errors
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "Failed to connect to webhook URL (timeout or invalid URL)",
        })
    }
    defer resp.Body.Close()

    // Check if the response status code indicates success (2xx)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(Response{
            Success: false,
            Message: "Webhook URL validation failed: received status " + resp.Status,
        })
    }

    // Logic to save the configuration would go here.
    // For this implementation, we simulate a successful save.

    // Return success response
    return ctx.Status(fiber.StatusOK).JSON(Response{
        Success: true,
        Message: "Webhook configured successfully",
    })
}

func main() {
    app := fiber.New()

    // Define the route
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server
    // Using default port 3000
    err := app.Listen(":3000")
    if err != nil {
        panic(err)
    }
}

