    lowerHost := strings.ToLower(host)

    // Check for localhost variations
    if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" {
        return true
    }

    // Check for private IP patterns (basic check)
    // This is a simplified check; for production, parse IP and check against ranges
