package main

import (
    "encoding/json"
    "net/http"
    "time"

    "github.com/gofiber/fiber/v2"
)

// ConfigureWebhook handles the POST request to configure a webhook.
// It validates the URL by sending a GET request with a 3-second timeout
// and returns a JSON response indicating the result.
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Define a struct to parse the incoming JSON body
    type RequestBody struct {
        WebhookURL string `json:"webhook_url"`
    }

    var req RequestBody

    // Parse the JSON body
    if err := ctx.BodyParser(&req); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error":   "Invalid JSON format",
            "success": false,
        })
    }

    // Validate that the webhook_url is provided
    if req.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error":   "webhook_url is required",
            "success": false,
        })
    }

    // Create a custom HTTP client with a 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Send a GET request to the webhook URL to validate it
    resp, err := client.Get(req.WebhookURL)
    if err != nil {
        // If there is an error (e.g., timeout, connection refused), return failure
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error":   "Failed to validate webhook URL: " + err.Error(),
            "success": false,
        })
    }
    // Ensure the response body is closed to prevent leaks
    defer resp.Body.Close()

    // Check if the response status code is within the 200-299 range
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "error":   "Webhook URL returned non-success status code: " + resp.Status,
            "success": false,
        })
    }

    // In a real application, you would save the configuration here.
    // For this example, we simply return a success message.

    return ctx.JSON(fiber.Map{
        "message": "Webhook configured and validated successfully",
        "success": true,
    })
}

func main() {
    app := fiber.New()

    // Define the route for the webhook configuration
    app.Post("/configure-webhook", ConfigureWebhook)

    // Start the server on port 3000
    err := app.Listen(":3000")
    if err != nil {
        panic(err)
    }
}

